export default function HistoryPage() {
  const { token } = theme.useToken();
  const { t } = useI18n(["storageLocker", "platform", "common"]);
  const [activeTab, setActiveTab] = useState("sensor");
  const [dates, setDates] = useState<any>([dayjs().subtract(7, 'day'), dayjs()]);

  const sensorColumns = [
    { title: t("storageLocker:dashboard.lockerName"), dataIndex: "storageNm", key: "storageNm" },
    { title: `${t("storageLocker:dashboard.temp")} (°C)`, dataIndex: "temp", key: "temp", align: "center" as const },
    { title: `${t("storageLocker:dashboard.humi")} (%)`, dataIndex: "humi", key: "humi", align: "center" as const },
    { title: t("common:datetime"), dataIndex: "time", key: "time", sorter: true },
  ];

  const controlColumns = [
    { title: t("storageLocker:dashboard.lockerName"), dataIndex: "storageNm", key: "storageNm" },
    { 
      title: t("storageLocker:navigation.control") || "제어 명령", 
      dataIndex: "control", 
      key: "control",
      render: (text: string) => <Tag color="blue">{text}</Tag>
    },
    { 
      title: t("common:status"), 
      dataIndex: "result", 
      key: "result",
      render: (text: string) => <Tag color={text === "Success" ? "success" : "error"}>{text}</Tag>
    },
    { title: t("common:worker"), dataIndex: "admin", key: "admin" },
    { title: t("common:datetime"), dataIndex: "time", key: "time" },
  ];

  const tabItems = [
    {
      key: "sensor",
      label: <span><LineChartOutlined /> {t("storageLocker:navigation.historySensor")}</span>,
      children: (
        <Table 
          columns={sensorColumns} 
          dataSource={mockSensorLogs} 
          rowKey="id" 
          pagination={{ pageSize: 15 }} 
          size="middle"
        />
      ),
    },
    {
      key: "control",
      label: <span><ThunderboltOutlined /> {t("storageLocker:navigation.historyControl")}</span>,
      children: (
        <Table 
          columns={controlColumns} 
          dataSource={mockControlLogs} 
          rowKey="id" 
          pagination={{ pageSize: 15 }} 
          size="middle"
        />
      ),
    },
  ];

  const handleExportXlsx = async () => {
    const data = activeTab === "sensor" ? mockSensorLogs : mockControlLogs;
    const fileName = activeTab === "sensor" ? "Sensor_History" : "Control_History";
    const success = await exportToExcel(data, fileName, activeTab);
    if (success) {
      message.success(`${t("common:exportXlsx")} ${t("storageLocker:dashboard.ctrlSuccess")}`);
    } else {
      message.error(t("storageLocker:dashboard.ctrlFail") || "Export Failed");
    }
  };

  return (
    <div style={{ padding: 24, display: "flex", flexDirection: "column", gap: 24, height: "100%", overflow: "auto" }}>
      {/* Header & Filter */}
      <Card bordered={false} bodyStyle={{ padding: "16px 24px" }} style={{ boxShadow: "0 2px 8px rgba(0,0,0,0.05)" }}>
        <Title level={4} style={{ marginBottom: 20 }}>
          <HistoryOutlined style={{ marginRight: 8, color: token.colorPrimary }} />
          {t("storageLocker:navigation.history")}
        </Title>
        
        <Row gutter={[16, 16]} align="middle">
          <Col xs={24} md={8} lg={6}>
            <Text style={{ display: "block", marginBottom: 4 }}>{t("storageLocker:dashboard.lockerName")}</Text>
            <Select 
              mode="multiple"
              placeholder={t("storageLocker:dashboard.selectPlaceholder")}
              style={{ width: "100%" }}
              options={mockStorages.map((s: any) => ({ label: s.name, value: s.id }))}
              allowClear
              maxTagCount="responsive"
            />
          </Col>
          <Col xs={24} md={10} lg={8}>
            <Text style={{ display: "block", marginBottom: 4 }}>{t("common:period")}</Text>
            <RangePicker 
              style={{ width: "100%" }} 
              value={dates}
              onChange={setDates}
              ranges={{
                [t("common:today")]: [dayjs(), dayjs()],
                [t("common:last7Days")]: [dayjs().subtract(7, 'day'), dayjs()],
                [t("common:last30Days")]: [dayjs().subtract(30, 'day'), dayjs()],
              }}
            />
          </Col>
          <Col xs={24} md={6} lg={10} style={{ paddingTop: 22 }}>
            <Space>
              <Button type="primary" icon={<SearchOutlined />}>{t("common:search")}</Button>
              <Button icon={<ExportOutlined />} onClick={handleExportXlsx}>{t("common:exportXlsx")}</Button>
            </Space>
          </Col>
        </Row>
      </Card>

      {/* Main Content with Tabs */}
      <Card bordered={false} bodyStyle={{ padding: "8px 24px 24px" }} style={{ flex: 1, boxShadow: "0 2px 8px rgba(0,0,0,0.05)" }}>
        <Tabs 
          activeKey={activeTab} 
          onChange={setActiveTab} 
          items={tabItems} 
          indicatorSize={(origin) => origin - 16}
        />
      </Card>
      
      <div style={{ textAlign: "right" }}>
        <Text type="secondary" style={{ fontSize: 12 }}>
          <ContainerOutlined style={{ marginRight: 4 }} />
          {t("common:total")}: {activeTab === "sensor" ? mockSensorLogs.length : mockControlLogs.length} {t("common:unit_record")}
        </Text>
      </div>
    </div>
  );
}
